cd /workspace && python3 -c "
from collections import defaultdict

# Try with more normal buckets
for n_normal in [10, 50, 100, 500]:
    for spike in [100, 500, 1000]:
        counts = {i: 1 for i in range(n_normal)}
        counts[n_normal] = spike
        values = list(counts.values())
        mean = sum(values) / len(values)
        var = sum((v - mean) ** 2 for v in values) / len(values)
        std = var ** 0.5
        threshold = mean + 3 * std
        if spike > threshold:
            print(f'n_normal={n_normal}, spike={spike}: mean={mean:.2f}, std={std:.2f}, threshold={threshold:.2f}, EXCEEDS')
"
